import React, { useState, useEffect, useCallback } from 'react';

const AddLaborHour = ({ apiBaseUrl }) => {
    const [projects, setProjects] = useState([]);
    const [selectedProjectId, setSelectedProjectId] = useState('');
    const [employeeName, setEmployeeName] = useState('');
    const [hours, setHours] = useState('');
    const [date, setDate] = useState('');

    const fetchAPI = useCallback(async (url, options = {}) => {
        const authToken = sessionStorage.getItem('authToken');
        const response = await fetch(url, {
          ...options,
          headers: {
            ...options.headers,
            'Authorization': `Bearer ${authToken}`,
            'Content-Type': 'application/json',
          },
        });
        if (!response.ok) {
          const errorResponse = await response.json();
          throw new Error(errorResponse.message || `Error fetching ${url}`);
        }
        return response;
      }, []);
    

    useEffect(() => {
        async function fetchProjects() {
            try {
                const response = await fetchAPI(`${apiBaseUrl}/projectsAPI`);
                setProjects(response);
            } catch (error) {
                console.error('Error fetching projects:', error);
            }
        }

        fetchProjects();
    }, [apiBaseUrl, fetchAPI]);

    const handleSubmit = async (event) => {
        event.preventDefault();
        const payload = {
            employeeName,
            projectId: selectedProjectId,
            hours,
            date
        };

        await fetch(`${apiBaseUrl}/addLaborHours`, {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json'
            },
            body: JSON.stringify(payload)
        });

        // Reset form (optional)
        setSelectedProjectId('');
        setEmployeeName('');
        setHours('');
        setDate('');
    };

    return (
        <form onSubmit={handleSubmit}>
            <input
                type="text"
                value={employeeName}
                onChange={(e) => setEmployeeName(e.target.value)}
                placeholder="Employee Name"
                required
            />
            <input
                type="date"
                value={date}
                onChange={(e) => setDate(e.target.value)}
                required
            />
            <select
                value={selectedProjectId}
                onChange={(e) => setSelectedProjectId(e.target.value)}
                required
            >
                <option value="">Select a Project</option>
                {projects.map(project => (
                    <option key={project.ProjectID} value={project.ProjectID}>{project.ProjectName}</option>
                ))}
            </select>
            <input
                type="number"
                min="0"
                step="0.25"
                value={hours}
                onChange={(e) => setHours(e.target.value)}
                placeholder="Hours Worked"
                required
            />
            <button type="submit">Submit</button>
        </form>
    );
};

export default AddLaborHour;
